// Deno-specific code
import * as dntShim from "../_dnt.shims.js";
import { join as stdJoin, dirname as stdDirname, basename as stdBasename, extname as stdExtname, isAbsolute as stdIsAbsolute, resolve as stdResolve, relative as stdRelative, } from "../deps/deno.land/std@0.170.0/path/mod.js";
export function cwd() {
    return dntShim.Deno.cwd();
}
export async function stat(path) {
    return await dntShim.Deno.stat(path);
}
export async function readTextFile(path) {
    return await dntShim.Deno.readTextFile(path);
}
export async function writeTextFile(path, data) {
    return await dntShim.Deno.writeTextFile(path, data);
}
export async function mkdir(path, opts) {
    return await dntShim.Deno.mkdir(path, opts);
}
export function join(...segments) {
    return stdJoin(...segments);
}
export function dirname(path) {
    return stdDirname(path);
}
export function basename(path, ext) {
    return stdBasename(path, ext);
}
export function extname(path) {
    return stdExtname(path);
}
export function isAbsolute(path) {
    return stdIsAbsolute(path);
}
export function resolve(...segments) {
    return stdResolve(...segments);
}
export function relative(from, to) {
    return stdRelative(from, to);
}
export function realPathSync(path) {
    return dntShim.Deno.realPathSync(path);
}
export function execPath() {
    return dntShim.Deno.execPath();
}
export function run(cmd) {
    return dntShim.Deno.run({ cmd });
}
